mapper.select:
WITH RECURSIVE QNA_CTE AS ( SELECT QNA_CD, PARENT_QNA_CD, TITLE, CONTENTS, HIT_COUNT, DEL_YN, INSERT_USER_CD, INSERT_DT, QNA_CD AS ordering FROM DOCS_QNA WHERE PARENT_QNA_CD IS NULL AND DEL_YN = 'N' UNION ALL SELECT Q.QNA_CD, Q.PARENT_QNA_CD, Q.TITLE, Q.CONTENTS, Q.HIT_COUNT, Q.DEL_YN, Q.INSERT_USER_CD, Q.INSERT_DT, QNA_CTE.ordering FROM DOCS_QNA Q INNER JOIN QNA_CTE ON Q.PARENT_QNA_CD = QNA_CTE.QNA_CD WHERE Q.DEL_YN = 'N' ) SELECT * FROM ( SELECT QNA_CTE.*, ROW_NUMBER() OVER (ORDER BY ordering) AS PAGEINDEX FROM QNA_CTE WHERE 1=1
AND TITLE LIKE '%' || #{title} || '%'
AND INSERT_DT BETWEEN #{insertStartDt}::date AND #{insertEndDt}::date + INTERVAL '1 DAY'
AND INSERT_USER_CD = #{insertUserNm}
) AS subquery WHERE 1=1
AND PAGEINDEX >= #{start}
LIMIT #{end}

SELECT COUNT(*) AS TOTAL_COUNT FROM ( SELECT QNA_CD, PARENT_QNA_CD, TITLE, CONTENTS, HIT_COUNT, DEL_YN, INSERT_USER_CD, INSERT_DT, ROW_NUMBER() OVER () AS PAGEINDEX FROM DOCS_QNA WHERE DEL_YN = 'N'
AND INSERT_DT BETWEEN #{insertStartDt}::date AND #{insertEndDt}::date + INTERVAL '1 DAY'
AND INSERT_USER_CD = #{insertUserNm}
AND TITLE LIKE '%' || #{title} || '%'
) AS subquery

