UPDATE DOCS_QNA
SET HIT_COUNT = COALESCE(HIT_COUNT, 0) + 1
WHERE QNA_CD = #{qnaCd}

UPDATE DOCS_QNA
SET DEL_YN = 'Y'
WHERE QNA_CD = #{qnaCd}
